SELECT AVG(performance_rating) AS average_performance_level
FROM player_performance
WHERE strftime('%Y', date) = '2023';

SELECT name, rating, email
FROM players
WHERE player_id = (SELECT white_player_id FROM games WHERE game_id = 0);

SELECT COUNT(game_id) AS total_games
FROM game_tournament
WHERE tournament_id = 1;

SELECT AVG(DISTINCT p.rating) 
FROM players p
JOIN user_game_log ug ON p.player_id = ug.user_id;

SELECT AVG(performance_rating) AS average_rating
FROM player_performance
WHERE player_id = 1;

SELECT name, country 
FROM players 
WHERE rating = (
  SELECT MAX(rating) 
  FROM players
);
